const ticketItem = $input.first();
const ticketData = ticketItem.json;

// Get comments from Zendesk response
const comments = ticketData.comments || [];
const commentBodies = comments.map(c => c.body || '').join(' ');

// Build full text block for scanning
const fullText = [
  ticketData.subject || '',
  ticketData.description || '',
  commentBodies
].join(' ').toLowerCase();

// Keyword map
const intentMap = [
  {
    keywords: ['chargeback', 'fraud', 'payment dispute', '3ds', 'stripe', 'chargeback'],
    pain_point: 'Risk of fraud and payment disputes',
    addon: 'Guesty Pay & Guesty Pay Protect (3DS)'
  },
  {
    keywords: ['damage waiver', 'security deposit', 'liability', 'insurance', 'safely', 'truvi', 'shield'],
    pain_point: 'Friction around insurance and damage protection',
    addon: 'Guesty Shield'
  },
  {
    keywords: ['lock', 'remotelock', 'lynx', 'operto', 'nuki', 'smart lock', 'keyless'],
    pain_point: 'High overhead from manual lock workflows',
    addon: 'Guesty Locks'
  },
  {
    keywords: ['occupancy', 'adr', 'revenue', 'pricing', 'pricelabs', 'beyond', 'wheelhouse', 'dynamic pricing'],
    pain_point: 'Underperforming revenue and occupancy',
    addon: 'GPO (Guesty Price Optimizer)'
  },
  {
    keywords: ['review', 'reply', 'messaging', 'guest communication', 'hostai', 'replyai', 'bad review', 'response'],
    pain_point: 'Low guest engagement and review management',
    addon: 'GCS / ReplyAI'
  },
  {
    keywords: ['direct reservation', 'direct booking', 'website', 'boostly', 'direct channel'],
    pain_point: 'Seeking to increase direct bookings',
    addon: 'Guesty Website'
  },
  {
    keywords: ['hubspot', 'quickbooks', 'integration', 'connect', 'conduit', 'api connect', 'guestyconnect'],
    pain_point: 'Seeking to connect a 3rd party tool via Guesty',
    addon: 'GuestyConnect'
  }
];

// Find first matching intent
let detected = null;
for (const intent of intentMap) {
  for (const kw of intent.keywords) {
    if (fullText.includes(kw)) {
      detected = intent;
      break;
    }
  }
  if (detected) break;
}

// No match -- skip this ticket
if (!detected) {
  return [];
}

// Return enriched ticket data
return [{
  json: {
    ticket_id: ticketData.ticket_id,
    account_id: ticketData.account_id,
    account_name: ticketData.account_name,
    subject: ticketData.subject,
    description: ticketData.description,
    requester_email: ticketData.requester_email,
    requester_name: ticketData.requester_name,
    csm: ticketData.csm,
    account_segment: ticketData.account_segment,
    package: ticketData.package,
    sf_account_id: ticketData.sf_account_id,
    detected_pain_point: detected.pain_point,
    recommended_addon: detected.addon,
    TEST_MODE: ticketData.TEST_MODE,
    TEST_EMAIL: ticketData.TEST_EMAIL
  }
}];

// Collect all items -- marketplace rows + carry-forward ticket data
const allItems = $input.all();

// Partner -> Guesty In-House upsell map
const partnerMap = [
  { partners: ['pricelabs', 'beyond', 'wheelhouse'], guesty: 'GPO (Guesty Price Optimizer)', msg: 'did you know Guesty native GPO could consolidate your pricing workflow and save you fees?' },
  { partners: ['stripe', 'chargeautomation'], guesty: 'GuestyPay', msg: 'did you know Guesty Pay could simplify your payment stack and reduce transaction fees?' },
  { partners: ['remotelock', 'lynx', 'operto', 'nuki'], guesty: 'Guesty Locks', msg: 'did you know Guesty Locks integrates natively and removes the need for a 3rd party middleman?' },
  { partners: ['safely', 'truvi'], guesty: 'Guesty Shield', msg: 'did you know Guesty Shield offers the same protection built right into your dashboard?' },
  { partners: ['hostai app', 'conduit', 'besty'], guesty: 'ReplyAI', msg: 'did you know Guesty ReplyAI is a native messaging solution that handles this automatically?' },
  { partners: ['touch stay', 'stayfi', 'enso connect', 'duve', 'hostbuddy ai'], guesty: 'GuestApp', msg: 'did you know Guesty GuestApp covers this natively and keeps everything in one place?' },
  { partners: ['key data dashboard'], guesty: 'Analytics Add-on', msg: 'did you know Guesty Analytics Add-on provides the same insights built into your account?' },
  { partners: ['autohost'], guesty: 'GuestVerify', msg: 'did you know Guesty GuestVerify handles guest screening natively?' },
  { partners: ['chekin'], guesty: 'AutoComply', msg: 'did you know Guesty AutoComply handles compliance check-in natively?' },
  { partners: ['vrplatform', 'ximplifi'], guesty: 'Guesty Accounting', msg: 'did you know Guesty Accounting covers this natively and syncs in real time?' },
  { partners: ['boostly'], guesty: 'Advanced Booking Website', msg: 'did you know Guesty offers a native Advanced Booking Website that converts better?' }
];

// Extract partner names from BQ rows
const partnerNames = allItems
  .map(i => (i.json.partner_name || '').toLowerCase())
  .filter(p => p.length > 0);

// Find first matching upsell
let partnerUpsellLine = '';
for (const entry of partnerMap) {
  const matched = entry.partners.find(p => partnerNames.some(pn => pn.includes(p)));
  if (matched) {
    const displayName = matched.charAt(0).toUpperCase() + matched.slice(1);
    partnerUpsellLine = 'I noticed you are using ' + displayName + ' -- ' + entry.msg;
    break;
  }
}

// Pull ticket context from first item (all rows share same ticket)
const ctx = allItems[0].json;

// Close date = today + 30 days
const closeDate = new Date();
closeDate.setDate(closeDate.getDate() + 30);
const closeDateStr = closeDate.toISOString().split('T')[0];

// SF Opportunity details (for test mode Slack display)
const oppName = 'GUS Upsell - ' + (ctx.account_name || '') + ' - ' + (ctx.recommended_addon || '');

return [{
  json: {
    ticket_id: ctx.ticket_id,
    account_id: ctx.account_id,
    account_name: ctx.account_name,
    subject: ctx.subject,
    requester_email: ctx.requester_email,
    requester_name: ctx.requester_name,
    csm: ctx.csm,
    csm_email: ctx.csm_email || '',
    sf_owner_id: ctx.sf_owner_id || '',
    sf_account_id: ctx.sf_account_id,
    account_segment: ctx.account_segment,
    detected_pain_point: ctx.detected_pain_point,
    recommended_addon: ctx.recommended_addon,
    partner_upsell_line: partnerUpsellLine,
    opp_name: oppName,
    opp_close_date: closeDateStr,
    TEST_MODE: ctx.TEST_MODE,
    TEST_EMAIL: ctx.TEST_EMAIL
  }
}];

